     3→
     4→syntax = "proto3";
     5→
     6→package tetragon;
     7→
     8→import "google/protobuf/timestamp.proto";
     9→import "google/protobuf/wrappers.proto";
    10→import "tetragon/bpf.proto";
    11→import "tetragon/capabilities.proto";
    12→
    13→option go_package = "github.com/cilium/tetragon/api/v1/tetragon";
    14→
    15→message Image {
    16→  // Identifier of the container image composed of the registry path and the
    17→  // sha256.
    18→  string id = 1;
    19→  // Name of the container image composed of the registry path and the tag.
    20→  string name = 2;
    21→}
    22→
    23→message SecurityContext {
    24→  // True if this container is priviledged.
    25→  bool privileged = 1;
    26→}
    27→
    28→message Container {
    29→  // Identifier of the container.
    30→  string id = 1;
    31→  // Name of the container.
    32→  string name = 2;
    33→  // Image of the container.
    34→  Image image = 3;
    35→  // Start time of the container.
    36→  google.protobuf.Timestamp start_time = 4;
    37→  // Process identifier in the container namespace.
    38→  google.protobuf.UInt32Value pid = 5;
    39→  // If this is set true, it means that the process might have been originated from
    40→  // a Kubernetes exec probe. For this field to be true, the following must be true:
    41→  // 1. The binary field matches the first element of the exec command list for either
    42→  //    liveness or readiness probe excluding the basename. For example, "/bin/ls"
    43→  //    and "ls" are considered a match.
    44→  // 2. The arguments field exactly matches the rest of the exec command list.
    45→  bool maybe_exec_probe = 13;
    46→  // The security context of the container
    47→  SecurityContext security_context = 14;
    48→}
    49→
    50→message Pod {
    51→  // Kubernetes namespace of the Pod.
    52→  string namespace = 1;
    53→  // Name of the Pod.
    54→  string name = 2;
    55→  // Container of the Pod from which the process that triggered the event
    56→  // originates.
    57→  Container container = 4;
    58→  // Contains all the labels of the pod.
    59→  map<string, string> pod_labels = 5;
    60→  // Kubernetes workload of the Pod.
    61→  string workload = 6;
    62→  // Kubernetes workload kind (e.g. "Deployment", "DaemonSet") of the Pod.
    63→  string workload_kind = 7;
    64→  // Contains all the annotations of the pod.
    65→  map<string, string> pod_annotations = 8;
    66→}
    67→
    68→message Capabilities {
    69→  // Permitted set indicates what capabilities the process can use. This is a
    70→  // limiting superset for the effective capabilities that the thread may
    71→  // assume. It is also a limiting superset for the capabilities that may be
    72→  // added to the inheritable set by a thread without the CAP_SETPCAP in its
    73→  // effective set.
    74→  repeated CapabilitiesType permitted = 1;
    75→  // Effective set indicates what capabilities are active in a process. This
    76→  // is the set used by the kernel to perform permission checks for the
    77→  // thread.
    78→  repeated CapabilitiesType effective = 2;
    79→  // Inheritable set indicates which capabilities will be inherited by the
    80→  // current process when running as a root user.
    81→  repeated CapabilitiesType inheritable = 3;
    82→}
    83→
    84→message Namespace {
    85→  // Inode number of the namespace.
    86→  uint32 inum = 1;
    87→  // Indicates if namespace belongs to host.
    88→  bool is_host = 2;
    89→}
    90→
    91→message Namespaces {
    92→  // Hostname and NIS domain name.
    93→  Namespace uts = 1;
    94→  // System V IPC, POSIX message queues.
    95→  Namespace ipc = 2;
    96→  // Mount points.
    97→  Namespace mnt = 3;
    98→  // Process IDs.
    99→  Namespace pid = 4;
   100→  // Process IDs for children processes.
   101→  Namespace pid_for_children = 5;
   102→  // Network devices, stacks, ports, etc.
   103→  Namespace net = 6;
   104→  // Boot and monotonic clocks.
   105→  Namespace time = 7;
   106→  // Boot and monotonic clocks for children processes.
   107→  Namespace time_for_children = 8;
   108→  // Cgroup root directory.
   109→  Namespace cgroup = 9;
   110→  // User and group IDs.
   111→  Namespace user = 10;
   112→}
   113→
   114→message UserNamespace {
   115→  // Nested level of the user namespace. Init or host user namespace is at level 0.
   116→  google.protobuf.Int32Value level = 1;
   117→  // The owner user ID of the namespace
   118→  google.protobuf.UInt32Value uid = 2;
   119→  // The owner group ID of the namepace.
   120→  google.protobuf.UInt32Value gid = 3;
   121→  // The user namespace details that include the inode number of the namespace.
   122→  Namespace ns = 4;
   123→}
   124→
   125→message ProcessCredentials {
   126→  // The real user ID of the process' owner.
   127→  google.protobuf.UInt32Value uid = 1;
   128→  // The real group ID of the process' owner.
   129→  google.protobuf.UInt32Value gid = 2;
   130→  // The effective user ID used for permission checks.
   131→  google.protobuf.UInt32Value euid = 3;
   132→  // The effective group ID used for permission checks.
   133→  google.protobuf.UInt32Value egid = 4;
   134→  // The saved user ID.
   135→  google.protobuf.UInt32Value suid = 5;
   136→  // The saved group ID.
   137→  google.protobuf.UInt32Value sgid = 6;
   138→  // the filesystem user ID used for filesystem access checks. Usually equals the euid.
   139→  google.protobuf.UInt32Value fsuid = 7;
   140→  // The filesystem group ID used for filesystem access checks. Usually equals the egid.
   141→  google.protobuf.UInt32Value fsgid = 8;
   142→  // Secure management flags
   143→  repeated SecureBitsType securebits = 9;
   144→  // Set of capabilities that define the permissions the process can execute with.
   145→  Capabilities caps = 10;
   146→  // User namespace where the UIDs, GIDs and capabilities are relative to.
   147→  UserNamespace user_ns = 11;
   148→}
   149→
   150→message InodeProperties {
   151→  // The inode number
   152→  uint64 number = 1;
   153→  // The inode links on the file system. If zero means the file is only in memory
   154→  google.protobuf.UInt32Value links = 2;
   155→}
   156→
   157→message FileProperties {
   158→  // Inode of the file
   159→  InodeProperties inode = 1;
   160→  // Path of the file
   161→  string path = 2;
   162→}
   163→
   164→message BinaryProperties {
   165→  // If set then this is the set user ID used for execution
   166→  google.protobuf.UInt32Value setuid = 1;
   167→  // If set then this is the set group ID used for execution
   168→  google.protobuf.UInt32Value setgid = 2;
   169→  // The reasons why this binary execution changed privileges. Usually this happens when the process executes
   170→  // a binary with the set-user-ID to root or file capability sets.
   171→  // The final granted privileges can be listed inside the `process_credentials` or capabilities fields part of of the `process` object.
   172→  repeated ProcessPrivilegesChanged privileges_changed = 3;
   173→  // File properties in case the executed binary is:
   174→  // 1. An anonymous shared memory file https://man7.org/linux/man-pages/man7/shm_overview.7.html.
   175→  // 2. An anonymous file obtained with memfd API https://man7.org/linux/man-pages/man2/memfd_create.2.html.
   176→  // 3. Or it was deleted from the file system.
   177→  FileProperties file = 4;
   178→}
   179→
   180→// User records
   181→message UserRecord {
   182→  // The UNIX username for this record. Corresponds to `pw_name` field of [struct passwd](https://man7.org/linux/man-pages/man3/getpwnam.3.html)
   183→  // and the `sp_namp` field of [struct spwd](https://man7.org/linux/man-pages/man3/getspnam.3.html).
   184→  string name = 1;
   185→}
   186→
   187→message Process {
   188→  // Exec ID uniquely identifies the process over time across all the nodes in the cluster.
   189→  string exec_id = 1;
   190→  // Process identifier from host PID namespace.
   191→  google.protobuf.UInt32Value pid = 2;
   192→  // The effective User identifier used for permission checks. This field maps to the
   193→  // 'ProcessCredentials.euid' field. Run with the `--enable-process-cred` flag to
   194→  // enable 'ProcessCredentials' and get all the User and Group identifiers.
   195→  google.protobuf.UInt32Value uid = 3;
   196→  // Current working directory of the process.
   197→  string cwd = 4;
   198→  // Absolute path of the executed binary.
   199→  string binary = 5;
   200→  // Arguments passed to the binary at execution.
   201→  string arguments = 6;
   202→  // Flags are for debugging purposes only and should not be considered a
   203→  // reliable source of information. They hold various information about
   204→  // which syscalls generated events, use of internal Tetragon buffers,
   205→  // errors and more.
   206→  // - `execve` This event is generated by an execve syscall for a new
   207→  // process. See procFs for the other option. A correctly formatted event
   208→  // should either set execve or procFS (described next).
   209→  // - `procFS` This event is generated from a proc interface. This happens
   210→  // at Tetragon init when existing processes are being loaded into Tetragon
   211→  // event buffer. All events should have either execve or procFS set.
   212→  // - `truncFilename` Indicates a truncated processes filename because the
   213→  // buffer size is too small to contain the process filename. Consider
   214→  // increasing buffer size to avoid this.
   215→  // - `truncArgs` Indicates truncated the processes arguments because the
   216→  // buffer size was too small to contain all exec args. Consider increasing
   217→  // buffer size to avoid this.
   218→  // - `taskWalk` Primarily useful for debugging. Indicates a walked process
   219→  // hierarchy to find a parent process in the Tetragon buffer. This may
   220→  // happen when we did not receive an exec event for the immediate parent of
   221→  // a process. Typically means we are looking at a fork that in turn did
   222→  // another fork we don't currently track fork events exactly and instead
   223→  // push an event with the original parent exec data. This flag can provide
   224→  // this insight into the event if needed.
   225→  // - `miss` An error flag indicating we could not find parent info in the
   226→  // Tetragon event buffer. If this is set it should be reported to Tetragon
   227→  // developers for debugging. Tetragon will do its best to recover
   228→  // information about the process from available kernel data structures
   229→  // instead of using cached info in this case. However, args will not be
   230→  // available.
   231→  // - `needsAUID` An internal flag for Tetragon to indicate the audit has
   232→  // not yet been resolved. The BPF hooks look at this flag to determine if
   233→  // probing the audit system is necessary.
   234→  // - `errorFilename` An error flag indicating an error happened while
   235→  // reading the filename. If this is set it should be reported to Tetragon
   236→  // developers for debugging.
   237→  // - `errorArgs` An error flag indicating an error happened while reading
   238→  // the process args. If this is set it should be reported to Tetragon
   239→  // developers for debugging
   240→  // - `needsCWD` An internal flag for Tetragon to indicate the current
   241→  // working directory has not yet been resolved. The Tetragon hooks look at
   242→  // this flag to determine if probing the CWD is necessary.
   243→  // - `noCWDSupport` Indicates that CWD is removed from the event because
   244→  // the buffer size is too small. Consider increasing buffer size to avoid
   245→  // this.
   246→  // - `rootCWD` Indicates that CWD is the root directory. This is necessary
   247→  // to inform readers the CWD is not in the event buffer and is '/' instead.
   248→  // - `errorCWD` An error flag indicating an error occurred while reading
   249→  // the CWD of a process. If this is set it should be reported to Tetragon
   250→  // developers for debugging.
   251→  // - `clone` Indicates the process issued a clone before exec*. This is the
   252→  // general flow to exec* a new process, however its possible to replace the
   253→  // current process with a new process by doing an exec* without a clone. In
   254→  // this case the flag will be omitted and the same PID will be used by the
   255→  // kernel for both the old process and the newly exec'd process.
   256→  // - `unknown` Indicates the process was not found in the process cache
   257→  // and contains just pid and start time.
   258→  string flags = 7;
   259→  // Start time of the execution.
   260→  google.protobuf.Timestamp start_time = 8;
   261→  // Audit user ID, this ID is assigned to a user upon login and is inherited
   262→  // by every process even when the user's identity changes. For example, by
   263→  // switching user accounts with su - john.
   264→  google.protobuf.UInt32Value auid = 9;
   265→  // Information about the the Kubernetes Pod where the event originated.
   266→  Pod pod = 10;
   267→  // The 15 first digits of the container ID.
   268→  string docker = 11;
   269→  // Exec ID of the parent process.
   270→  string parent_exec_id = 12;
   271→  // Reference counter from the Tetragon process cache.
   272→  uint32 refcnt = 13;
   273→  // Set of capabilities that define the permissions the process can execute with.
   274→  Capabilities cap = 14;
   275→  // Linux namespaces of the process, disabled by default, can be enabled by
   276→  // the `--enable-process-ns` flag.
   277→  Namespaces ns = 15;
   278→  // Thread ID, note that for the thread group leader, tid is equal to pid.
   279→  google.protobuf.UInt32Value tid = 16;
   280→  // Process credentials, disabled by default, can be enabled by the
   281→  // `--enable-process-cred` flag.
   282→  ProcessCredentials process_credentials = 17;
   283→  // Executed binary properties. This field is only available on ProcessExec events.
   284→  BinaryProperties binary_properties = 18;
   285→  // UserRecord contains user information about the event.
   286→  // It is only supported when i) Tetragon is running as a systemd service or directly on the host, and
   287→  // ii) when the flag `--username-metadata` is set to "unix". In this case, the information is retrieved from
   288→  // the traditional user database `/etc/passwd` and no name services lookups are performed.
   289→  // The resolution will only be attempted for processes in the host namespace.
   290→  // Note that this resolution happens in user-space, which means that mapping might have changed
   291→  // between the in-kernel BPF hook being executed and the username resolution.
   292→  UserRecord user = 19;
   293→  // If set to true, this process is containerized and is a member of the
   294→  // process tree rooted at pid=1 in its PID namespace. This is useful if,
   295→  // for example, you wish to discern whether a process was spawned using a
   296→  // tool like nsenter or kubectl exec.
   297→  google.protobuf.BoolValue in_init_tree = 20;
   298→}
   299→
   300→message ProcessExec {
   301→  // Process that triggered the exec.
   302→  Process process = 1;
   303→  // Immediate parent of the process.
   304→  Process parent = 2;
   305→  // Ancestors of the process beyond the immediate parent.
   306→  repeated Process ancestors = 3;
   307→}
   308→
   309→message ProcessExit {
   310→  // Process that triggered the exit.
   311→  Process process = 1;
   312→  // Immediate parent of the process.
   313→  Process parent = 2;
   314→  // Signal that the process received when it exited, for example SIGKILL or
   315→  // SIGTERM (list all signal names with `kill -l`). If there is no signal
   316→  // handler implemented for a specific process, we report the exit status
   317→  // code that can be found in the status field.
   318→  string signal = 3;
   319→  // Status code on process exit. For example, the status code can indicate
   320→  // if an error was encountered or the program exited successfully.
   321→  uint32 status = 4;
   322→  // Date and time of the event.
   323→  google.protobuf.Timestamp time = 5;
   324→  // Ancestors of the process beyond the immediate parent.
   325→  repeated Process ancestors = 6;
   326→}
   327→
   328→message KprobeSock {
   329→  string family = 1;
   330→  string type = 2;
   331→  string protocol = 3;
   332→  uint32 mark = 4;
   333→  uint32 priority = 5;
   334→  string saddr = 6;
   335→  string daddr = 7;
   336→  uint32 sport = 8;
   337→  uint32 dport = 9;
   338→  uint64 cookie = 10;
   339→  string state = 11;
   340→}
   341→
   342→message KprobeSkb {
   343→  uint32 hash = 1;
   344→  uint32 len = 2;
   345→  uint32 priority = 3;
   346→  uint32 mark = 4;
   347→  string saddr = 5;
   348→  string daddr = 6;
   349→  uint32 sport = 7;
   350→  uint32 dport = 8;
   351→  uint32 proto = 9;
   352→  uint32 sec_path_len = 10;
   353→  uint32 sec_path_olen = 11;
   354→  string protocol = 12;
   355→  string family = 13;
   356→}
   357→
   358→message KprobeSockaddr {
   359→  string family = 1;
   360→  string addr = 2;
   361→  uint32 port = 3;
   362→}
   363→
   364→message KprobeNetDev {
   365→  string name = 1;
   366→}
   367→
   368→message KprobePath {
   369→  string mount = 1;
   370→  string path = 2;
   371→  string flags = 3;
   372→  string permission = 4;
   373→}
   374→
   375→message KprobeFile {
   376→  string mount = 1;
   377→  string path = 2;
   378→  string flags = 3;
   379→  string permission = 4;
   380→}
   381→
   382→message KprobeTruncatedBytes {
   383→  bytes bytes_arg = 1;
   384→  uint64 orig_size = 2;
   385→}
   386→
   387→message KprobeCred {
   388→  repeated CapabilitiesType permitted = 1;
   389→  repeated CapabilitiesType effective = 2;
   390→  repeated CapabilitiesType inheritable = 3;
   391→}
   392→
   393→message KprobeLinuxBinprm {
   394→  string path = 1;
   395→  string flags = 2;
   396→  string permission = 3;
   397→}
   398→
   399→message KprobeCapability {
   400→  google.protobuf.Int32Value value = 1;
   401→  string name = 2;
   402→}
   403→
   404→message KprobeUserNamespace {
   405→  google.protobuf.Int32Value level = 1;
   406→  google.protobuf.UInt32Value owner = 2;
   407→  google.protobuf.UInt32Value group = 3;
   408→  Namespace ns = 4;
   409→}
   410→
   411→message KprobeBpfAttr {
   412→  string ProgType = 1;
   413→  uint32 InsnCnt = 2;
   414→  string ProgName = 3;
   415→}
   416→
   417→message KprobePerfEvent {
   418→  string KprobeFunc = 1;
   419→  string Type = 2;
   420→  uint64 Config = 3;
   421→  uint64 ProbeOffset = 4;
   422→}
   423→
   424→message KprobeBpfMap {
   425→  string MapType = 1;
   426→  uint32 KeySize = 2;
   427→  uint32 ValueSize = 3;
   428→  uint32 MaxEntries = 4;
   429→  string MapName = 5;
   430→}
   431→
   432→message SyscallId {
   433→  uint32 id = 1;
   434→  string abi = 2;
   435→}
   436→
   437→message KprobeArgument {
   438→  oneof arg {
   439→    string string_arg = 1;
   440→    int32 int_arg = 2;
   441→    KprobeSkb skb_arg = 3;
   442→    uint64 size_arg = 4;
   443→    bytes bytes_arg = 5;
   444→    KprobePath path_arg = 6;
   445→    KprobeFile file_arg = 7;
   446→    KprobeTruncatedBytes truncated_bytes_arg = 8;
   447→    KprobeSock sock_arg = 9;
   448→    KprobeCred cred_arg = 10;
   449→    int64 long_arg = 11;
   450→    KprobeBpfAttr bpf_attr_arg = 12;
   451→    KprobePerfEvent perf_event_arg = 13;
   452→    KprobeBpfMap bpf_map_arg = 14;
   453→    uint32 uint_arg = 15;
   454→    KprobeUserNamespace user_namespace_arg = 16 [deprecated = true];
   455→    KprobeCapability capability_arg = 17;
   456→    ProcessCredentials process_credentials_arg = 19;
   457→    UserNamespace user_ns_arg = 20;
   458→    KernelModule module_arg = 21;
   459→    string kernel_cap_t_arg = 22; // Capabilities in hexadecimal format.
   460→    string cap_inheritable_arg = 23; // Capabilities inherited by a forked process in hexadecimal format.
   461→    string cap_permitted_arg = 24; // Capabilities that are currently permitted in hexadecimal format.
   462→    string cap_effective_arg = 25; // Capabilities that are actually used in hexadecimal format.
   463→    KprobeLinuxBinprm linux_binprm_arg = 26;
   464→    KprobeNetDev net_dev_arg = 27;
   465→    BpfCmd bpf_cmd_arg = 28;
   466→    SyscallId syscall_id = 29;
   467→    KprobeSockaddr sockaddr_arg = 30;
   468→  }
   469→  string label = 18;
   470→}
   471→
   472→enum KprobeAction {
   473→  // Unknown action
   474→  KPROBE_ACTION_UNKNOWN = 0;
   475→  // Post action creates an event (default action).
   476→  KPROBE_ACTION_POST = 1;
   477→  // Post action creates a mapping between file descriptors and file names.
   478→  KPROBE_ACTION_FOLLOWFD = 2;
   479→  // Sigkill action synchronously terminates the process.
   480→  KPROBE_ACTION_SIGKILL = 3;
   481→  // Post action removes a mapping between file descriptors and file names.
   482→  KPROBE_ACTION_UNFOLLOWFD = 4;
   483→  // Override action modifies the return value of the call.
   484→  KPROBE_ACTION_OVERRIDE = 5;
   485→  // Post action dupplicates a mapping between file descriptors and file
   486→  // names.
   487→  KPROBE_ACTION_COPYFD = 6;
   488→  // GetURL action issue an HTTP Get request against an URL from userspace.
   489→  KPROBE_ACTION_GETURL = 7;
   490→  // GetURL action issue a DNS lookup against an URL from userspace.
   491→  KPROBE_ACTION_DNSLOOKUP = 8;
   492→  // NoPost action suppresses the transmission of the event to userspace.
   493→  KPROBE_ACTION_NOPOST = 9;
   494→  // Signal action sends specified signal to the process.
   495→  KPROBE_ACTION_SIGNAL = 10;
   496→  // TrackSock action tracks socket.
   497→  KPROBE_ACTION_TRACKSOCK = 11;
   498→  // UntrackSock action un-tracks socket.
   499→  KPROBE_ACTION_UNTRACKSOCK = 12;
   500→  // NotifyEnforcer action notifies enforcer sensor.
   501→  KPROBE_ACTION_NOTIFYENFORCER = 13;
   502→  // CleanupEnforcerNotification action cleanups any state left by NotifyEnforcer
   503→  KPROBE_ACTION_CLEANUPENFORCERNOTIFICATION = 14;
   504→}
   505→
   506→message ProcessKprobe {
   507→  // Process that triggered the kprobe.
   508→  Process process = 1;
   509→  // Immediate parent of the process.
   510→  Process parent = 2;
   511→  // Symbol on which the kprobe was attached.
   512→  string function_name = 3;
   513→  // Arguments definition of the observed kprobe.
   514→  repeated KprobeArgument args = 4;
   515→  // Return value definition of the observed kprobe.
   516→  KprobeArgument return = 5;
   517→  // Action performed when the kprobe matched.
   518→  KprobeAction action = 6;
   519→  // Kernel stack trace to the call.
   520→  repeated StackTraceEntry kernel_stack_trace = 7;
   521→  // Name of the Tracing Policy that created that kprobe.
   522→  string policy_name = 8;
   523→  // Action performed when the return kprobe executed.
   524→  KprobeAction return_action = 9;
   525→  // Short message of the Tracing Policy to inform users what is going on.
   526→  string message = 10;
   527→  // Tags of the Tracing Policy to categorize the event.
   528→  repeated string tags = 11;
   529→  // User-mode stack trace to the call.
   530→  repeated StackTraceEntry user_stack_trace = 12;
   531→  // Ancestors of the process beyond the immediate parent.
   532→  repeated Process ancestors = 13;
   533→}
   534→
   535→message ProcessTracepoint {
   536→  // Process that triggered the tracepoint.
   537→  Process process = 1;
   538→  // Immediate parent of the process.
   539→  Process parent = 2;
   540→  // Subsystem of the tracepoint.
   541→  string subsys = 4;
   542→  // Event of the subsystem.
   543→  string event = 5;
   544→  // Arguments definition of the observed tracepoint.
   545→  // TODO: once we implement all we want, rename KprobeArgument to GenericArgument
   546→  repeated KprobeArgument args = 6;
   547→  // Name of the policy that created that tracepoint.
   548→  string policy_name = 7;
   549→  // Action performed when the tracepoint matched.
   550→  KprobeAction action = 8;
   551→  // Short message of the Tracing Policy to inform users what is going on.
   552→  string message = 9;
   553→  // Tags of the Tracing Policy to categorize the event.
   554→  repeated string tags = 10;
   555→  // Ancestors of the process beyond the immediate parent.
   556→  repeated Process ancestors = 11;
   557→}
   558→
   559→message ProcessUprobe {
   560→  Process process = 1;
   561→  Process parent = 2;
   562→  string path = 3;
   563→  string symbol = 4;
   564→  // Name of the policy that created that uprobe.
   565→  string policy_name = 5;
   566→  // Short message of the Tracing Policy to inform users what is going on.
   567→  string message = 6;
   568→  // Arguments definition of the observed uprobe.
   569→  repeated KprobeArgument args = 7;
   570→  // Tags of the Tracing Policy to categorize the event.
   571→  repeated string tags = 8;
   572→  // Ancestors of the process beyond the immediate parent.
   573→  repeated Process ancestors = 9;
   574→  // uprobe offset (mutualy exclusive with symbol)
   575→  uint64 offset = 10;
   576→  // uprobe ref_ctr_offset
   577→  uint64 ref_ctr_offset = 11;
   578→}
   579→
   580→message ProcessUsdt {
   581→  Process process = 1;
   582→  Process parent = 2;
   583→  string path = 3;
   584→  string provider = 4;
   585→  string name = 5;
   586→  // Name of the policy that created that uprobe.
   587→  string policy_name = 6;
   588→  // Short message of the Tracing Policy to inform users what is going on.
   589→  string message = 7;
   590→  // Arguments definition of the observed uprobe.
   591→  repeated KprobeArgument args = 8;
   592→  // Tags of the Tracing Policy to categorize the event.
   593→  repeated string tags = 9;
   594→  // Ancestors of the process beyond the immediate parent.
   595→  repeated Process ancestors = 10;
   596→}
   597→
   598→message ProcessLsm {
   599→  Process process = 1;
   600→  Process parent = 2;
   601→  // LSM hook name.
   602→  string function_name = 3;
   603→  // Name of the policy that created that LSM hook.
   604→  string policy_name = 5;
   605→  // Short message of the Tracing Policy to inform users what is going on.
   606→  string message = 6;
   607→  // Arguments definition of the observed LSM hook.
   608→  repeated KprobeArgument args = 7;
   609→  // Action performed when the LSM hook matched.
   610→  KprobeAction action = 8;
   611→  // Tags of the Tracing Policy to categorize the event.
   612→  repeated string tags = 9;
   613→  // Ancestors of the process beyond the immediate parent.
   614→  repeated Process ancestors = 10;
   615→  // IMA file hash. Format algorithm:value.
   616→  string ima_hash = 11;
   617→}
   618→
   619→message KernelModule {
   620→  // Kernel module name
   621→  string name = 1;
   622→  // If true the module signature was verified successfully. Depends on kernels compiled with
   623→  // CONFIG_MODULE_SIG option, for details please read: https://www.kernel.org/doc/Documentation/admin-guide/module-signing.rst
   624→  google.protobuf.BoolValue signature_ok = 2;
   625→  // The module tainted flags that will be applied on the kernel. For further details please read: https://docs.kernel.org/admin-guide/tainted-kernels.html
   626→  repeated TaintedBitsType tainted = 3;
   627→}
   628→
   629→message Test {
   630→  uint64 arg0 = 1;
   631→  uint64 arg1 = 2;
   632→  uint64 arg2 = 3;
   633→  uint64 arg3 = 4;
   634→}
   635→
   636→enum HealthStatusType {
   637→  HEALTH_STATUS_TYPE_UNDEF = 0;
   638→  HEALTH_STATUS_TYPE_STATUS = 1;
   639→}
   640→
   641→enum HealthStatusResult {
   642→  HEALTH_STATUS_UNDEF = 0;
   643→  HEALTH_STATUS_RUNNING = 1;
   644→  HEALTH_STATUS_STOPPED = 2;
   645→  HEALTH_STATUS_ERROR = 3;
   646→}
   647→
   648→message GetHealthStatusRequest {
   649→  repeated HealthStatusType event_set = 1;
   650→}
   651→
   652→// Tainted bits to indicate if the kernel was tainted. For further details: https://docs.kernel.org/admin-guide/tainted-kernels.html
   653→enum TaintedBitsType {
   654→  TAINT_UNSET = 0;
   655→
   656→  /* A proprietary module was loaded. */
   657→  TAINT_PROPRIETARY_MODULE = 1;
   658→
   659→  /* A module was force loaded. */
   660→  TAINT_FORCED_MODULE = 2;
   661→
   662→  /* A module was force unloaded. */
   663→  TAINT_FORCED_UNLOAD_MODULE = 4;
   664→
   665→  /* A staging driver was loaded. */
   666→  TAINT_STAGED_MODULE = 1024;
   667→
   668→  /* An out of tree module was loaded. */
   669→  TAINT_OUT_OF_TREE_MODULE = 4096;
   670→
   671→  /* An unsigned module was loaded. Supported only on kernels built with CONFIG_MODULE_SIG option. */
   672→  TAINT_UNSIGNED_MODULE = 8192;
   673→
   674→  /* The kernel has been live patched. */
   675→  TAINT_KERNEL_LIVE_PATCH_MODULE = 32768;
   676→
   677→  /* Loading a test module. */
   678→  TAINT_TEST_MODULE = 262144;
   679→}
   680→
   681→message HealthStatus {
   682→  HealthStatusType event = 1;
   683→  HealthStatusResult status = 2;
   684→  string details = 3;
   685→}
   686→
   687→message GetHealthStatusResponse {
   688→  repeated HealthStatus health_status = 1;
   689→}
   690→
   691→// loader sensor event triggered for loaded binary/library
   692→message ProcessLoader {
   693→  Process process = 1;
   694→  string path = 2;
   695→  bytes buildid = 3;
   696→}
   697→
   698→// RuntimeHookRequest synchronously propagates information to the agent about run-time state.
   699→message RuntimeHookRequest {
   700→  oneof event {
   701→    CreateContainer createContainer = 1;
   702→  }
   703→}
   704→
   705→message RuntimeHookResponse {}
   706→
   707→// CreateContainer informs the agent that a container was created
   708→// This is intented to be used by OCI hooks (but not limited to them) and corresponds to the
   709→// CreateContainer hook:
   710→// https://github.com/opencontainers/runtime-spec/blob/main/config.md#createcontainer-hooks.
   711→//
   712→// The containerName, containerID, podName, podUID, and podNamespace fields are retrieved from the
   713→// annotations as a convenience, and may be left empty if the corresponding annotations are not
   714→// found.
   715→message CreateContainer {
   716→  // cgroupsPath is the cgroups path for the container. The path is expected to be relative to the
   717→  // cgroups mountpoint. See: https://github.com/opencontainers/runtime-spec/blob/58ec43f9fc39e0db229b653ae98295bfde74aeab/specs-go/config.go#L174
   718→  string cgroupsPath = 1;
   719→  // rootDir is the absolute path of the root directory of the container.
   720→  // See: https://github.com/opencontainers/runtime-spec/blob/main/specs-go/config.go#L174
   721→  string rootDir = 2;
   722→  // annotations are the run-time annotations for the container
   723→  // see https://github.com/opencontainers/runtime-spec/blob/main/config.md#annotations
   724→  map<string, string> annotations = 3;
   725→  // containerName is the name of the container
   726→  string containerName = 4;
   727→  // containerID is the id of the container
   728→  string containerID = 5;
   729→  // podName is the pod name
   730→  string podName = 6;
   731→  // podUID is the pod uid
   732→  string podUID = 7;
   733→  // podNamespace is the namespace of the pod
   734→  string podNamespace = 8;
   735→  // containerImage is the full image location (repo + image)
   736→  string containerImage = 9;
   737→}
   738→
   739→message StackTraceEntry {
   740→  // linear address of the function in kernel or user space.
   741→  uint64 address = 1;
   742→  // offset is the offset into the native instructions for the function.
   743→  uint64 offset = 2;
   744→  // symbol is the symbol name of the function.
   745→  string symbol = 3;
   746→  // module path for user space addresses.
   747→  string module = 4;
   748→}
