package main

import (
	"fmt"
	"testing"

	"github.com/cilium/tetragon/api/v1/tetragon"
	"github.com/cilium/tetragon/pkg/process"
	"github.com/cilium/tetragon/pkg/watcher"
	corev1 "k8s.io/api/core/v1"
	metav1 "k8s.io/apimachinery/pkg/apis/meta/v1"
)

type mockPodAccessor struct{}

func (m mockPodAccessor) FindContainer(containerID string) (*corev1.Pod, *corev1.ContainerStatus, bool) {
	// Create a pod with UID
	pod := &corev1.Pod{
		ObjectMeta: metav1.ObjectMeta{
			Name:      "test-pod",
			Namespace: "default",
			UID:       "test-pod-uid-123",
		},
	}

	containerStatus := &corev1.ContainerStatus{
		Name:        "test-container",
		ContainerID: "docker://container123",
		ImageID:     "docker://test/image@sha256:abc123",
		Image:       "test/image:latest",
		State: corev1.ContainerState{
			Running: &corev1.ContainerStateRunning{
				StartedAt: metav1.Now(),
			},
		},
	}

	return pod, containerStatus, true
}

func TestPodUIDInclusion(t *testing.T) {
	mockWatcher := mockPodAccessor{}

	// Test the getPodInfo function
	podInfo := process.GetPodInfo(mockWatcher, "docker://container123", "/bin/test", "args", 123)

	if podInfo == nil {
		t.Fatal("Expected podInfo to not be nil")
	}

	// Check if UID is included
	expectedUID := "test-pod-uid-123"
	if podInfo.Uid != expectedUID {
		t.Errorf("Expected UID '%s', but got '%s'", expectedUID, podInfo.Uid)
	}

	// Check other existing fields are preserved
	if podInfo.Name != "test-pod" {
		t.Errorf("Expected pod name 'test-pod', but got '%s'", podInfo.Name)
	}

	if podInfo.Namespace != "default" {
		t.Errorf("Expected namespace 'default', but got '%s'", podInfo.Namespace)
	}

	fmt.Printf("✅ Test passed: Pod UID '%s' is correctly included in the pod info\n", podInfo.Uid)
}

func main() {
	t := &testing.T{}
	TestPodUIDInclusion(t)
	if !t.Failed() {
		fmt.Println("✅ All tests passed! Pod UID is correctly included in Tetragon pod information.")
	}
}

